21	// newInstallCommand creates the "ddx install <name>" command.
22	func (f *CommandFactory) newInstallCommand() *cobra.Command {
23		cmd := &cobra.Command{
24			Use:   "install <name>",
25			Short: "Install a package or resource",
26			Long: `Install a package or resource from the DDx registry into the
27	current project under .ddx/plugins/<name>/.
28	
29	Examples:
30	  ddx install helix                        # Install HELIX workflow
31	  ddx install helix --force                # Reinstall even if already up to date
32	  ddx install persona/strict-code-reviewer # Install a single persona`,
33			Args: cobra.ExactArgs(1),
34			RunE: f.runInstall,
35		}
36		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
37		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
38		return cmd
39	}
