202	func prepareSymlinkTarget(target string, force bool) error {
203		if info, err := os.Lstat(target); err == nil {
204			if info.Mode()&os.ModeSymlink != 0 || force {
205				if err := os.RemoveAll(target); err != nil {
206					return fmt.Errorf("removing existing %s: %w", target, err)
207				}
208				return nil
209			}
210			return fmt.Errorf("%s already exists (use --force to replace)", target)
211		} else if !os.IsNotExist(err) {
212			return fmt.Errorf("checking existing %s: %w", target, err)
213		}
214		return nil
215	}
