383	// copyDirTree copies the source directory tree into dst as real files,
384	// returning the list of written file paths (relative to cwd).
385	func copyDirTree(src, dst string) ([]string, error) {
386		var written []string
387		err := filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
388			if err != nil {
389				return err
390			}
391			rel, relErr := filepath.Rel(src, path)
392			if relErr != nil {
393				return relErr
394			}
395			target := filepath.Join(dst, rel)
396			if info.IsDir() {
397				return os.MkdirAll(target, 0o755)
398			}
399			if info.Mode()&os.ModeSymlink != 0 {
400				// Skip plugin-source symlinks — never materialize.
401				return nil
402			}
403			if !info.Mode().IsRegular() {
404				return nil
405			}
406			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
407				return err
408			}
409			in, err := os.Open(path)
410			if err != nil {
411				return err
412			}
413			defer func() { _ = in.Close() }()
414			out, err := os.OpenFile(target, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, info.Mode())
415			if err != nil {
416				return err
417			}
418			if _, copyErr := io.Copy(out, in); copyErr != nil {
419				_ = out.Close()
420				return copyErr
421			}
422			if err := out.Close(); err != nil {
423				return err
424			}
425			written = append(written, target)
426			return nil
427		})
428		return written, err
429	}
