522	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
523		out := cmd.OutOrStdout()
524	
525		state, err := registry.LoadState()
526		if err != nil {
527			return fmt.Errorf("loading state: %w", err)
528		}
529	
530		if len(state.Installed) == 0 {
531			fmt.Fprintln(out, "No packages installed.")
532			return nil
533		}
534	
535		var totalIssues int
536		for _, entry := range state.Installed {
537			var issues []string
538			for _, f := range entry.Files {
539				expanded := registry.ExpandHome(f)
540				info, err := os.Lstat(expanded)
541				if os.IsNotExist(err) {
542					issues = append(issues, fmt.Sprintf("  missing: %s", f))
543					continue
544				}
545				if err != nil {
546					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
547					continue
548				}
549				// Check symlinks resolve.
550				if info.Mode()&os.ModeSymlink != 0 {
551					target, err := os.Readlink(expanded)
552					if err != nil {
553						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
554						continue
555					}
556					// Resolve relative symlinks against their parent directory.
557					if !filepath.IsAbs(target) {
558						target = filepath.Join(filepath.Dir(expanded), target)
559					}
560					if _, err := os.Stat(target); os.IsNotExist(err) {
561						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
562					}
563				}
564			}
565	
566			if len(issues) == 0 {
567				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
568			} else {
569				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
570				for _, issue := range issues {
571					fmt.Fprintln(out, issue)
572				}
573				totalIssues += len(issues)
574			}
575		}
576	
577		if totalIssues > 0 {
578			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
579		}
580		return nil
581	}
