608		for _, pkg := range results {
609			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n",
610				pkg.Name,
611				pkg.Version,
612				string(pkg.Type),
613				pkg.Description,
614			)
615		}
616		return w.Flush()
617	}
