619	func (f *CommandFactory) newOutdatedCommand() *cobra.Command {
620		cmd := &cobra.Command{
621			Use:   "outdated",
622			Short: "List installed packages with available updates",
623			Long:  `Check installed packages against the registry and list those with newer versions available.`,
624			Args:  cobra.NoArgs,
625			RunE:  f.runOutdated,
626		}
627		cmd.Flags().Bool("json", false, "Output as JSON")
628		return cmd
629	}
