631	func (f *CommandFactory) runOutdated(cmd *cobra.Command, args []string) error {
632		out := cmd.OutOrStdout()
633		asJSON, _ := cmd.Flags().GetBool("json")
634	
635		state, err := registry.LoadState()
636		if err != nil {
637			return fmt.Errorf("reading installed state: %w", err)
638		}
639		if len(state.Installed) == 0 {
640			fmt.Fprintln(out, "No packages installed.")
641			return nil
642		}
643	
644		reg := registry.BuiltinRegistry()
645	
646		type outdatedEntry struct {
647			Name             string `json:"name"`
648			InstalledVersion string `json:"installed_version"`
649			LatestVersion    string `json:"latest_version"`
650		}
651	
652		var outdated []outdatedEntry
653		for _, entry := range state.Installed {
654			pkg, err := reg.Find(entry.Name)
655			if err != nil {
656				continue // not in registry, skip
657			}
658			if pkg.Version != entry.Version {
659				outdated = append(outdated, outdatedEntry{
660					Name:             entry.Name,
661					InstalledVersion: entry.Version,
662					LatestVersion:    pkg.Version,
663				})
664			}
665		}
666	
667		if len(outdated) == 0 {
668			fmt.Fprintln(out, "All installed packages are up to date.")
669			return nil
670		}
671	
672		if asJSON {
673			enc := json.NewEncoder(out)
674			enc.SetIndent("", "  ")
675			return enc.Encode(outdated)
676		}
677	
678		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
679		fmt.Fprintln(w, "NAME\tINSTALLED\tLATEST")
680		for _, o := range outdated {
681			fmt.Fprintf(w, "%s\t%s\t%s\n", o.Name, o.InstalledVersion, o.LatestVersion)
682		}
683		return w.Flush()
684	}
