166	// validateSkillName rejects names that could escape the destination tree.
167	func validateSkillName(name string) error {
168		if name == "" || name == "." || name == ".." {
169			return fmt.Errorf("skills.Install: invalid skill name %q", name)
170		}
171		if strings.ContainsAny(name, `/\`) {
172			return fmt.Errorf("skills.Install: skill name contains path separator: %q", name)
173		}
174		if filepath.IsAbs(name) {
175			return fmt.Errorf("skills.Install: skill name is absolute: %q", name)
176		}
177		if strings.Contains(name, "..") {
178			return fmt.Errorf("skills.Install: skill name contains parent reference: %q", name)
179		}
180		return nil
181	}
182	
183	// assertWithinRoot resolves dest (and the existing portion of its path) and
184	// returns an error if it escapes absRoot via symlinks or absolute paths.
185	func assertWithinRoot(dest, absRoot string) error {
186		abs, err := filepath.Abs(dest)
187		if err != nil {
188			return fmt.Errorf("resolve %s: %w", dest, err)
189		}
190		// Walk upward to find an existing ancestor and EvalSymlinks on it; this
191		// catches symlink-escapes even when the leaf does not yet exist.
192		check := abs
193		for {
194			if _, err := os.Lstat(check); err == nil {
195				resolved, err := filepath.EvalSymlinks(check)
196				if err != nil {
197					return fmt.Errorf("resolve symlinks for %s: %w", check, err)
198				}
199				resolvedRoot, rerr := filepath.EvalSymlinks(absRoot)
200				if rerr != nil {
201					// projectRoot may not exist yet — fall back to lexical compare.
202					resolvedRoot = absRoot
203				}
204				if !pathHasPrefix(resolved, resolvedRoot) {
205					return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
206				}
207				break
208			}
209			parent := filepath.Dir(check)
210			if parent == check {
211				break
212			}
213			check = parent
214		}
215		if !pathHasPrefix(abs, absRoot) {
216			return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
217		}
218		return nil
219	}
220	
221	func pathHasPrefix(p, prefix string) bool {
222		if p == prefix {
223			return true
224		}
225		sep := string(filepath.Separator)
226		if !strings.HasSuffix(prefix, sep) {
227			prefix += sep
228		}
229		return strings.HasPrefix(p, prefix)
230	}
231	
232	// copyFromFS recursively copies src (rooted at ".") into destDir as real files.
233	// Symlinks in the source are skipped (never materialized) — see FEAT-015
234	// "Cross-platform invariant".
235	func copyFromFS(src fs.FS, destDir string) error {
236		if err := os.MkdirAll(destDir, 0o755); err != nil {
237			return err
238		}
239		return fs.WalkDir(src, ".", func(p string, d fs.DirEntry, err error) error {
240			if err != nil {
241				return err
242			}
243			if p == "." {
244				return nil
245			}
246			if strings.Contains(p, "..") {
247				return fmt.Errorf("invalid path in source: %s", p)
248			}
249			target := filepath.Join(destDir, p)
250			if d.IsDir() {
251				return os.MkdirAll(target, 0o755)
252			}
253			if d.Type()&os.ModeSymlink != 0 {
254				// Skip plugin-source symlinks — never materialize.
255				return nil
256			}
257			data, rerr := fs.ReadFile(src, p)
258			if rerr != nil {
259				return rerr
260			}
261			return os.WriteFile(target, data, 0o644)
262		})
263	}
