17	// InstallPackage downloads the source release tarball and copies declared install mappings
18	// into projectRoot. It records installed files (project-relative when possible) in the
19	// returned InstalledEntry.
20	func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
21		entry := InstalledEntry{
22			Name:        pkg.Name,
23			Version:     pkg.Version,
24			Type:        pkg.Type,
25			Source:      pkg.Source,
26			InstalledAt: time.Now(),
27		}
28	
29		// FEAT-015 early validation: if the package argument already declares a
30		// home-rooted Root.Target, reject it before doing any I/O. The post-
31		// manifest check below covers manifest-supplied targets after download.
32		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
33			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
34		}
35	
36		// Switch into projectRoot so relative install targets resolve against the
37		// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
38		// the recorded entry.Files paths project-relative.
39		if projectRoot != "" {
40			absProject, absErr := filepath.Abs(projectRoot)
41			if absErr == nil {
42				if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
43					if err := os.Chdir(absProject); err == nil {
44						defer func() { _ = os.Chdir(origDir) }()
45					}
46				}
47			}
48		}
49	
50		// Download and extract the release tarball to a temp directory.
51		tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
52		if err != nil {
53			return entry, fmt.Errorf("creating temp dir: %w", err)
54		}
55		defer func() { _ = os.RemoveAll(tmpDir) }()
56	
57		tarballURL := githubTarballURL(pkg.Source, pkg.Version)
58		extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
59		if err != nil {
60			return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
61		}
62	
63		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(extractedDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
64			if manifestPkg != nil {
65				pkg = manifestPkg
66			}
67		} else {
68			if len(manifestIssues) > 0 {
69				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
70			}
71			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
72		}
73	
74		if pkg.Install.Root == nil {
75			pkg.Install.Root = &InstallMapping{
76				Source: ".",
77				Target: defaultPackageRootTarget(pkg.Name),
78			}
79		}
80	
81		// FEAT-015: plugin install targets must be project-relative. Manifests
82		// that try to write into the user's home are rejected so plugins can't
83		// pollute global state.
84		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
85			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
86		}
87	
88		if issues := ValidatePackageStructure(extractedDir, pkg); len(issues) > 0 {
89			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
90		}
91	
92		// Process Root mapping — copy the plugin tree into the project-local
93		// install location (e.g. .ddx/plugins/<name>/).
94		var installedRoot string
95		files, err := copyMapping(extractedDir, pkg.Install.Root)
96		if err != nil {
97			return entry, fmt.Errorf("installing plugin root: %w", err)
98		}
99		entry.Files = append(entry.Files, files...)
100		installedRoot = ExpandHome(pkg.Install.Root.Target)
101	
102		// Ensure declared executables have the execute bit set.
103		for _, rel := range pkg.Install.Executable {
104			p := filepath.Join(installedRoot, filepath.FromSlash(rel))
105			if info, err := os.Stat(p); err == nil && !info.IsDir() {
106				_ = os.Chmod(p, info.Mode()|0111)
107			}
108		}
109	
110		// Process Skills via the shared installer. skills.Install copies real
111		// files into <projectRoot>/.agents/skills/ and <projectRoot>/.claude/skills/.
112		// No symlinks are ever created — this is the cross-platform invariant
113		// that FEAT-015 relies on.
114		if len(pkg.Install.Skills) > 0 {
115			// Use the extracted tarball as the skill source rather than the
116			// post-copy installed root: copyMapping skips broken symlinks (a
117			// known GitHub-tarball quirk), so the installed tree may have an
118			// empty .agents/skills/. The extracted dir preserves the original
119			// layout — including broken symlinks — and skills.discoverSkills
120			// recovers them via the skills/<name> fallback.
121			absExtracted, absErr := filepath.Abs(extractedDir)
122			if absErr != nil {
123				absExtracted = extractedDir
124			}
125			absProject, absErr := filepath.Abs(".")
126			if absErr != nil {
127				absProject = projectRoot
128			}
129			if err := skills.Install(os.DirFS(absExtracted), absProject, skills.Options{Force: true}); err != nil {
130				return entry, fmt.Errorf("installing skills: %w", err)
131			}
132			entry.Files = append(entry.Files, recordInstalledSkills(absExtracted, absProject)...)
133		}
134	
135		// Process Scripts mapping — copy the script to the target path.
136		// If the target is already a symlink, the developer is managing it
137		// themselves (e.g. symlink to their git checkout) — skip with a notice.
138		if pkg.Install.Scripts != nil {
139			dst := ExpandHome(pkg.Install.Scripts.Target)
140			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
141				target, _ := os.Readlink(dst)
142				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
143				entry.Files = append(entry.Files, dst)
144			} else {
145				srcDir := extractedDir
146				if installedRoot != "" {
147					srcDir = installedRoot
148				}
149				files, err := copyMapping(srcDir, pkg.Install.Scripts)
150				if err != nil {
151					return entry, fmt.Errorf("installing scripts: %w", err)
152				}
153				entry.Files = append(entry.Files, files...)
154	
155				// Ensure the installed script is executable.
156				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
157					_ = os.Chmod(dst, info.Mode()|0111)
158				}
159			}
160		}
161	
162		// Process symlinks.
163		for _, sym := range pkg.Install.Symlinks {
164			src := ExpandHome(sym.Source)
165			dst := ExpandHome(sym.Target)
166	
167			// Create parent dir if needed.
168			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
169				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
170			}
171	
172			// Remove existing symlink/file if present.
173			if _, err := os.Lstat(dst); err == nil {
174				if err := os.RemoveAll(dst); err != nil {
175					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
176				}
177			}
178	
179			if err := os.Symlink(src, dst); err != nil {
180				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
181			}
182			entry.Files = append(entry.Files, dst)
183		}
184	
185		return entry, nil
186	}
187	
188	// recordInstalledSkills returns project-relative paths to the skill directories
189	// installed under .agents/skills/ and .claude/skills/ that came from the given
190	// plugin root.
191	func recordInstalledSkills(installedRoot, projectRoot string) []string {
192		var names []string
193		for _, candidate := range []string{
194			filepath.Join(installedRoot, ".agents", "skills"),
195			filepath.Join(installedRoot, "skills"),
196		} {
197			entries, err := os.ReadDir(candidate)
198			if err != nil {
199				continue
200			}
201			for _, e := range entries {
202				if e.IsDir() || e.Type()&os.ModeSymlink != 0 {
203					names = append(names, e.Name())
204				}
205			}
206			if len(names) > 0 {
207				break
208			}
209		}
210	
211		var files []string
212		for _, name := range names {
213			for _, sub := range []string{".agents/skills", ".claude/skills"} {
214				rel := filepath.Join(filepath.FromSlash(sub), name)
215				files = append(files, rel)
216			}
217		}
218		return files
219	}
