221	// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
222	// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
223	func InstallResource(resourcePath string) (InstalledEntry, error) {
224		entry := InstalledEntry{
225			Name:        resourcePath,
226			Version:     "latest",
227			Type:        PackageTypeResource,
228			Source:      "https://github.com/DocumentDrivenDX/ddx-library",
229			InstalledAt: time.Now(),
230		}
231	
232		// resourcePath is like "persona/strict-code-reviewer"
233		parts := strings.SplitN(resourcePath, "/", 2)
234		if len(parts) != 2 {
235			return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
236		}
237		resourceType, resourceName := parts[0], parts[1]
238	
239		// Determine target directory relative to cwd.
240		target := filepath.Join(".ddx", "plugins", "ddx", resourceType+"s")
241		if err := os.MkdirAll(target, 0755); err != nil {
242			return entry, fmt.Errorf("creating target directory %s: %w", target, err)
243		}
244	
245		// Fetch raw file from GitHub.
246		rawURL := fmt.Sprintf(
247			"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
248			resourceType, resourceName,
249		)
250	
251		destFile := filepath.Join(target, resourceName+".md")
252		if err := downloadFile(rawURL, destFile); err != nil {
253			return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
254		}
255	
256		entry.Files = append(entry.Files, destFile)
257		return entry, nil
258	}
259	
260	// UninstallPackage removes files recorded in the entry.
261	func UninstallPackage(entry *InstalledEntry) error {
262		var errs []string
263		for _, f := range entry.Files {
