289	func downloadAndExtract(url, destDir string) (string, error) {
290		resp, err := http.Get(url) //nolint:noctx
291		if err != nil {
292			return "", fmt.Errorf("fetching %s: %w", url, err)
293		}
294		defer func() { _ = resp.Body.Close() }()
295	
296		if resp.StatusCode != http.StatusOK {
297			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
298		}
299	
300		gz, err := gzip.NewReader(resp.Body)
301		if err != nil {
302			return "", fmt.Errorf("reading gzip: %w", err)
303		}
304		defer func() { _ = gz.Close() }()
305	
306		tr := tar.NewReader(gz)
307		var topDir string
308	
309		for {
310			hdr, err := tr.Next()
311			if err == io.EOF {
312				break
313			}
314			if err != nil {
315				return "", fmt.Errorf("reading tar: %w", err)
316			}
317	
318			// Sanitize path to prevent directory traversal.
319			clean := filepath.Clean(hdr.Name)
320			if strings.HasPrefix(clean, "..") {
321				continue
322			}
323	
324			dest := filepath.Join(destDir, clean)
325	
326			// Skip PAX global headers (GitHub tarballs include these).
327			if hdr.Typeflag == tar.TypeXGlobalHeader {
328				continue
329			}
330	
331			// Track the top-level directory name.
332			parts := strings.SplitN(clean, string(filepath.Separator), 2)
333			if topDir == "" && parts[0] != "" && parts[0] != "." {
334				topDir = parts[0]
335			}
336	
337			switch hdr.Typeflag {
338			case tar.TypeDir:
339				if err := os.MkdirAll(dest, 0755); err != nil {
340					return "", err
341				}
342			case tar.TypeReg:
343				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
344					return "", err
345				}
346				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
347				if err != nil {
348					return "", err
349				}
350				if _, err := io.Copy(f, tr); err != nil {
351					_ = f.Close()
352					return "", err
353				}
354				_ = f.Close()
355			case tar.TypeSymlink:
356				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
357					return "", err
358				}
359				_ = os.Remove(dest)
360				if err := os.Symlink(hdr.Linkname, dest); err != nil {
361					return "", err
362				}
363			}
364		}
365	
366		if topDir == "" {
367			return destDir, nil
368		}
369		return filepath.Join(destDir, topDir), nil
